export const projectText = (slug: string, locale: string): ProjectText => {
  const entry = projectContent[slug]
  if (!entry) {
    return { title: slug, typology: '', location: '', dates: '', summary: '', description: '' }
  }
  return entry[locale === 'fr' ? 'fr' : 'en']
}
